package org.apache.commons.csv;

import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;

import java.io.IOException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatPrintAndEscapeTest {

    private CSVFormat csvFormat;
    private Appendable out;

    @BeforeEach
    void setUp() {
        // Use DEFAULT which has delimiter COMMA and escape DOUBLE_QUOTE_CHAR by default
        csvFormat = CSVFormat.DEFAULT.withDelimiter(COMMA).withEscape('\"');
        out = new StringBuilder();
    }

    private void invokePrintAndEscape(CharSequence value, int offset, int len, Appendable out) throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        method.setAccessible(true);
        method.invoke(csvFormat, value, offset, len, out);
    }

    @Test
    void testPrintAndEscape_NoSpecialChars() throws Exception {
        String input = "simpletext";
        invokePrintAndEscape(input, 0, input.length(), out);
        assertEquals("simpletext", out.toString());
    }

    @Test
    void testPrintAndEscape_WithDelimiter() throws Exception {
        // delimiter is comma ','
        String input = "hello,world";
        invokePrintAndEscape(input, 0, input.length(), out);
        // The comma should be escaped with quote character '"'
        // So output should be "hello" + escape + ',' + "world"
        // escape char is '"', delimiter is ','
        String expected = "hello\"\",world";
        // But per code, it appends escape char + the char, so for ',' it appends '"' + ','
        // So output is "hello" + '"' + ',' + "world" => hello",world
        // So expected is "hello\",world"
        expected = "hello\"\,world".replace("\\,", ","); // to clarify
        // Actually, output is "hello" + '"' + ',' + "world" => hello",world
        expected = "hello\",world";
        assertEquals(expected, out.toString());
    }

    @Test
    void testPrintAndEscape_WithEscapeChar() throws Exception {
        // Escape char is '"'
        String input = "escape\"char";
        invokePrintAndEscape(input, 0, input.length(), out);
        // The double quote character should be escaped by prefixing escape char
        // So output is "escape" + '"' + '"' + "char"
        String expected = "escape\"\"char";
        assertEquals(expected, out.toString());
    }

    @Test
    void testPrintAndEscape_WithCRandLF() throws Exception {
        String input = "line1\r\nline2\nline3\rend";
        invokePrintAndEscape(input, 0, input.length(), out);
        // CR is replaced with 'r' escaped, LF with 'n' escaped
        // escape char is '"'
        // So output:
        // line1 + '"' + 'r' + '"' + 'n' + line2 + '"' + 'n' + line3 + '"' + 'r' + end
        StringBuilder expected = new StringBuilder();
        expected.append("line1").append('"').append('r').append('"').append('n');
        expected.append("line2").append('"').append('n').append("line3").append('"').append('r').append("end");
        assertEquals(expected.toString(), out.toString());
    }

    @Test
    void testPrintAndEscape_EmptyInput() throws Exception {
        String input = "";
        invokePrintAndEscape(input, 0, 0, out);
        assertEquals("", out.toString());
    }

    @Test
    void testPrintAndEscape_OffsetAndLength() throws Exception {
        String input = "abcdefg";
        // offset 2, length 3 => "cde"
        invokePrintAndEscape(input, 2, 3, out);
        assertEquals("cde", out.toString());
    }

    @Test
    void testPrintAndEscape_AllSpecialChars() throws Exception {
        // delimiter=',' escape='"'
        String input = "" + CR + LF + ',' + '"';
        invokePrintAndEscape(input, 0, input.length(), out);
        // Each special char escaped with escape char and replaced if CR or LF
        // CR -> 'r', LF -> 'n'
        StringBuilder expected = new StringBuilder();
        expected.append('"').append('r');
        expected.append('"').append('n');
        expected.append('"').append(',');
        expected.append('"').append('"');
        assertEquals(expected.toString(), out.toString());
    }

    @Test
    void testPrintAndEscape_WithDifferentEscapeAndDelimiter() throws Exception {
        // Use INFORMIX_UNLOAD which has delimiter PIPE '|' and escape BACKSLASH '\\'
        csvFormat = CSVFormat.INFORMIX_UNLOAD;
        out = new StringBuilder();
        String input = "a|b\\c\r\n";
        invokePrintAndEscape(input, 0, input.length(), out);
        // delimiter = '|', escape = '\\'
        // So '|' and '\\' and CR LF are escaped
        // CR -> 'r', LF -> 'n'
        // output: a + '\' + '|' + b + '\' + '\' + c + '\' + 'r' + '\' + 'n'
        StringBuilder expected = new StringBuilder();
        expected.append("a").append('\\').append('|').append("b").append('\\').append('\\').append("c").append('\\').append('r').append('\\').append('n');
        assertEquals(expected.toString(), out.toString());
    }
}
